+/**
+ * Categorize a command into a task type for analytics.
+ * Uses pattern matching to group similar operations together.
+ * Patterns are checked in order of specificity.
+ */
+function categorizeCommand(command: string): string {
+  const cmd = command.toLowerCase();
+
+  // Git operations (check early - "git push" shouldn't match shell patterns)
+  if (cmd.startsWith("git ") || cmd.includes(" git ")) {
+    return "git";
+  }
+
+  // Build/test operations
+  if (
+    cmd.includes("test") ||
+    cmd.includes("build") ||
+    cmd.includes("compile") ||
+    cmd.startsWith("npm ") ||
+    cmd.includes(" npm ") ||
+    cmd.startsWith("bun ") ||
+    cmd.includes(" bun ")
+  ) {
+    return "build_test";
+  }
+
+  // Search operations
+  if (
+    cmd.includes("grep") ||
+    cmd.startsWith("rg ") ||
+    cmd.includes(" rg ") ||
+    cmd.startsWith("find ") ||
+    cmd.includes(" find ") ||
+    cmd.includes("search") ||
+    cmd.includes("glob")
+  ) {
+    return "search";
+  }
+
+  // File read operations
+  if (
+    cmd.includes("read") ||
+    cmd.startsWith("cat ") ||
+    cmd.includes(" cat ") ||
+    cmd.startsWith("head ") ||
+    cmd.includes(" head ")
+  ) {
+    return "read";
+  }
+
+  // File write operations
+  if (
+    cmd.includes("write") ||
+    cmd.includes("edit") ||
+    cmd.startsWith("sed ") ||
+    cmd.includes(" sed ") ||
+    cmd.includes("patch")
+  ) {
+    return "write";
+  }
+
+  // Shell execution (check last - use word boundaries to avoid false positives)
+  if (
+    cmd.includes("bash") ||
+    cmd.startsWith("sh ") ||
+    cmd.includes(" sh ") ||
+    /\bexec\b/.test(cmd)
+  ) {
+    return "execute";
+  }
+
+  return "other";
+}
